30	architecture tb of psi_common_delay_cfg_tb is
31	  constant period_c : time                                                := (1 sec) / real(freq_clk_g);
32	  --*** stimuli ***
33	  signal clk_sti    : std_logic                                           := '0';
34	  signal rst_sti    : std_logic                                           := '1';
35	  signal dat_sti    : std_logic_vector(Width_g - 1 downto 0)              := (others => '0');
36	  signal str_sti    : std_logic                                           := '0';
37	  signal del_sti    : std_logic_vector(log2ceil(max_delay_g) - 1 downto 0) := to_uslv(Delay_g, log2ceil(max_delay_g));
38	  --*** observable signals ***
