42	  --*** Procedure for constant delay check **
43	  procedure delay_cst_proc(signal delOut : out std_logic_vector;
44	                           signal strOut : out std_logic;
45	                           signal datOut : out std_logic_vector;
46	                           signal datIn  : in std_logic_vector;
