147	    for i in 0 to from_uslv(del_sti) + 200 loop
148	      dat_sti <= std_logic_vector(to_unsigned(i, Width_g));
149	      if i = 75 then
150	        prev_delay_v := from_uslv(del_sti);
151	        del_sti      <= to_uslv(13, del_sti'length);
152	        print(">> change delay 33 -> 13");
153	      end if;
154	
155	      if i < from_uslv(del_sti) + 1 then
156	        StdlvCompareInt(0, dat_obs, "Out data wrong", false);
157	      elsif i >= 75 and i <= 75 + 3 then
