162	      end if;
163	      wait until rising_edge(clk_sti);
164	    end loop;
165	
166	    wait for from_uslv(del_sti) * period_c;
167	
168	    -------------------------------------------------------------------
169	    --*** change delay from 15 to 10
170	    del_sti <= to_uslv(10, del_sti'length);
171	    str_sti <= '0';
172	    wait for period_c;
173	    wait until rising_edge(clk_sti);
174	    hold_v  := dat_obs;
175	
