181	      str_sti <= '1';
182	      dat_sti <= std_logic_vector(to_unsigned(i, Width_g));
183	      if i < from_uslv(del_sti) then
184	        StdlvCompareStdlv(hold_v, dat_obs, "Out data wrong");
185	      else
186	        StdlvCompareInt(i - from_uslv(del_sti), dat_obs, " Out data wrong");
187	      end if;
188	      wait until rising_edge(clk_sti);
189	      str_sti <= '0';
190	      WaitClockCycles(3, clk_sti);
191	    end loop;
192	    prev_value_v := from_uslv(dat_sti);
193	
194	    -------------------------------------------------------------------
